parameters.jsCode:
const results = [...$('Fetch Maps Results (Page 1)').all(), ...$input.all()];
const companies = [];

results.forEach(item => {
  if (item.json.places) {
    item.json.places.forEach(place => {
      if (place.phoneNumber) {
        const company = {
          name: place.title || '',
          phone: place.phoneNumber || '',
          website: place.website,
          rating: place.rating || null,
          type: place.type || ''
        };

        companies.push(company);
      }
    });
  }
});

return companies.map(company => ({json: company}));

// scan entire HTML + response text
const html = JSON.stringify($json).toLowerCase();

function extract(patterns) {
  for (const pattern of patterns) {
    const matches = html.match(pattern);
    if (matches && matches.length) {
      return clean(matches[0]);
    }
  }
  return "-";
}

// remove tracking & redirect junk
function clean(url) {
  return url
    .replace(/\\u002f/g, "/")
    .split("?")[0]
    .replace(/amp;/g, "");
}

// ---------- SOCIAL DETECTION ----------

// Instagram
const instagram = extract([
  /https?:\/\/[^"'<> ]*instagram\.com[^"'<> ]*/gi,
  /instagr\.am\/[^"'<> ]*/gi,
  /instagram:[^"'<> ]+/gi
]);

// Facebook
const facebook = extract([
  /https?:\/\/[^"'<> ]*facebook\.com[^"'<> ]*/gi,
  /fb\.com\/[^"'<> ]*/gi
]);

// LinkedIn
const linkedin = extract([
  /https?:\/\/[^"'<> ]*linkedin\.com[^"'<> ]*/gi
]);

// Twitter / X
const twitter = extract([
  /https?:\/\/[^"'<> ]*(twitter|x)\.com[^"'<> ]*/gi
]);

// YouTube
const youtube = extract([
  /https?:\/\/[^"'<> ]*youtube\.com[^"'<> ]*/gi
]);

// TikTok
const tiktok = extract([
  /https?:\/\/[^"'<> ]*tiktok\.com[^"'<> ]*/gi
]);


// ---------- EMAIL EXTRACTION ----------
function extractEmails(html) {

  const text = html
    .replace(/\[at\]/gi, "@")
    .replace(/\(at\)/gi, "@")
    .replace(/\s+at\s+/gi, "@")
    .replace(/\[dot\]/gi, ".")
    .replace(/\(dot\)/gi, ".")
    .replace(/\s+dot\s+/gi, ".");

  const emailRegex = /mailto:([a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,})|([a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,})/gi;

  const matches = [...text.matchAll(emailRegex)].map(m => m[1] || m[2]);

  const badPatterns = [
    "example.com",
    "domain.com",
    "email.com",
    "test.com",
    "user@",
    "admin@domain",
    "yourname@",
    "noreply@",
    "donotreply@"
  ];

  const cleaned = matches
    .map(e => e.toLowerCase().trim())
    .filter(e =>
      e &&
      !badPatterns.some(b => e.includes(b))
    );

  return [...new Set(cleaned)];
}

// run extraction
const emails = extractEmails(html);

// choose best email
const email = emails.length ? emails[0] : "";


return {
  ...$('Extract Businesses From Maps').item.json,
  email,
  instagram,
  facebook,
  linkedin,
  twitter,
  youtube,
  tiktok
};

// Business name
const name = ($json.name || "").replace(/[^\w\s]/gi, '').trim();


// Optional: add city if available
const city = ($json.city || "").trim();

// Remove accents (é → e)
const normalize = str =>
  str.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

// Clean symbols & punctuation
const clean = normalize(name)
  .replace(/&/g, " and ")
  .replace(/\+/g, " and ")
  .replace(/@/g, "")
  .replace(/'/g, "")
  .replace(/\./g, "")
  .replace(/-/g, " ")
  .replace(/\//g, " ")
  .replace(/\s+/g, " ")
  .trim();

// Remove noise business words (optional but improves accuracy)
const noiseWords = [
  "cafe","bakery","restaurant","shop","store",
  "kitchen","bar","grill","coffee","house"
];

const simplified = clean
  .split(" ")
  .filter(w => !noiseWords.includes(w.toLowerCase()))
  .join(" ");

// Build search variations
const variations = [
  `"${name}"`,
  `"${clean}"`,
  `"${simplified}"`,
  clean,
  simplified
];

// Add location variations (if available)
if (city) {
  variations.push(`"${name}" ${city}`);
  variations.push(`${clean} ${city}`);
}

// Remove duplicates & empty strings
const uniqueQueries = [...new Set(variations.filter(Boolean))];

// Force search only social platforms
const socialSites = `
(site:instagram.com OR
 site:facebook.com OR
 site:linkedin.com OR
 site:tiktok.com OR
 site:youtube.com OR
 site:twitter.com OR
 site:x.com)
`;

// Build final search query
const finalQuery = `${uniqueQueries.join(" OR ")} ${socialSites}`;

return {
  ...$json,
  smartQuery: finalQuery
};

function clean(url) {
  if (!url || url === "-") return "";

  const badPatterns = [
    "/p/",              // instagram posts
    "/reel/",
    "watch?v=",         // youtube videos
    "youtu.be/",
    "discover",         // tiktok discover pages
    "/video/",
    "/videos/",
    "share",
    "sharer",
    "intent",
    "status"
  ];

  const lower = url.toLowerCase();

  for (const bad of badPatterns) {
    if (lower.includes(bad)) return "";
  }

  return url.trim().replace(/\/$/, "");
}


function username(url){
  if(!url) return "";
  return url.split("/").pop().toLowerCase();
}

function merge(primary, fallback) {

  const p = clean(primary);
  const f = clean(fallback);

  // CASE: nothing found
  if (!p && !f) {
    return { url: "-", confidence: "LOW" };
  }

  // CASE: website only
  if (p && !f) {
    return { url: p, confidence: "HIGH" };
  }

  // CASE: serper only
  if (!p && f) {
    return { url: f, confidence: "MEDIUM" };
  }

  // CASE: both exist & same handle
  if (username(p) === username(f)) {
    return { url: p, confidence: "HIGH" };
  }

  // CASE: both exist but different
  return {
    url: `${p} | ${f}`,
    confidence: "MEDIUM"
  };
}

const instagram = merge($json.instagram, $json.serperInstagram);
const facebook  = merge($json.facebook, $json.serperFacebook);
const linkedin  = merge($json.linkedin, $json.serperLinkedin);
const twitter   = merge($json.twitter, $json.serperTwitter);
const youtube   = merge($json.youtube, $json.serperYoutube);
const tiktok    = merge($json.tiktok, $json.serperTiktok);

return {
  ...$json,

  instagram: instagram.url,
  instagramConfidence: instagram.confidence,

  facebook: facebook.url,
  facebookConfidence: facebook.confidence,

  linkedin: linkedin.url,
  linkedinConfidence: linkedin.confidence,

  twitter: twitter.url,
  twitterConfidence: twitter.confidence,

  youtube: youtube.url,
  youtubeConfidence: youtube.confidence,

  tiktok: tiktok.url,
  tiktokConfidence: tiktok.confidence
};

function safe(value) {
  if (value === undefined || value === null) return "-";
  if (typeof value === "string" && value.trim() === "") return "-";
  return value;
}

return {
  json: {

    // BUSINESS INFO
    name: safe($json.name),
    website: safe($json.website),
    phone: safe($json.phone),
    rating: safe($json.rating),
    type: safe($json.type),

    // EMAIL (important for validation)
    email: $json.email || "",

    // SOCIALS
    instagram: safe($json.instagram),
    facebook: safe($json.facebook),
    linkedin: safe($json.linkedin),
    twitter: safe($json.twitter),
    youtube: safe($json.youtube),
    tiktok: safe($json.tiktok),

    // CONFIDENCE
    instagramConfidence: safe($json.instagramConfidence) || "LOW",
    facebookConfidence: safe($json.facebookConfidence) || "LOW",
    linkedinConfidence: safe($json.linkedinConfidence) || "LOW",
    twitterConfidence: safe($json.twitterConfidence) || "LOW",
    youtubeConfidence: safe($json.youtubeConfidence) || "LOW",
    tiktokConfidence: safe($json.tiktokConfidence) || "LOW"

  }
};

const original = $('Check Email Exists').item.json;
const result = $json.result || $json.status || "";

let email = original.email || "";
let emailStatus = "VALID";

if (result === "invalid" || result === "undeliverable") {
  email = "";
  emailStatus = "NOT_FOUND_OR_INVALID";
}
else if (result === "risky" || result === "catch-all" || result === "unknown") {
