    // SOCIALS
    instagram: original.instagram || "-",
    facebook: original.facebook || "-",
    linkedin: original.linkedin || "-",
    twitter: original.twitter || "-",
    youtube: original.youtube || "-",
    tiktok: original.tiktok || "-",

    // CONFIDENCE
    instagramConfidence: original.instagramConfidence || "LOW",
    facebookConfidence: original.facebookConfidence || "LOW",
    linkedinConfidence: original.linkedinConfidence || "LOW",
    twitterConfidence: original.twitterConfidence || "LOW",
    youtubeConfidence: original.youtubeConfidence || "LOW",
    tiktokConfidence: original.tiktokConfidence || "LOW"
  }
};

const data = $json;

return {
  json: {

    // BUSINESS INFO
    name: data.name || "-",
    website: data.website || "-",
    phone: data.phone || "-",
    rating: data.rating || "-",
    type: data.type || "-",

    // EMAIL
