    // SOCIALS
    instagram: data.instagram || "-",
    facebook: data.facebook || "-",
    linkedin: data.linkedin || "-",
    twitter: data.twitter || "-",
    youtube: data.youtube || "-",
    tiktok: data.tiktok || "-",

    // CONFIDENCE
    instagramConfidence: data.instagramConfidence || "LOW",
    facebookConfidence: data.facebookConfidence || "LOW",
    linkedinConfidence: data.linkedinConfidence || "LOW",
    twitterConfidence: data.twitterConfidence || "LOW",
    youtubeConfidence: data.youtubeConfidence || "LOW",
    tiktokConfidence: data.tiktokConfidence || "LOW"

  }
};

function safe(value) {
  if (value === undefined || value === null) return "-";
  if (typeof value === "string" && value.trim() === "") return "-";
  return value;
}


function formatPhone(phone) {
  if (!phone || phone === "-") return "-";

  // remove everything except digits and +
  phone = phone.toString().replace(/[^\d+]/g, "");

  // remove leading +
  phone = phone.replace(/^\+/, "");

  // if too short → return original
  if (phone.length < 7) return phone;

  // detect country code (1–3 digits)
  let countryCode = "";
  let rest = "";

  if (phone.length > 10) {
    countryCode = phone.slice(0, phone.length - 10);
    rest = phone.slice(-10);
  } else {
    rest = phone;
  }

  // US-style formatting
  if (!countryCode && rest.length === 10) {
    const formatted = `(${rest.slice(0,3)}) ${rest.slice(3,6)}-${rest.slice(6)}`;
    return `'${formatted}`;   // force text for Sheets
  }

  // group remaining digits nicely
  function groupDigits(num) {
    return num.replace(/(\d{2,4})(?=\d)/g, "$1 ");
  }

  const formattedIntl = `(+${countryCode}) ${groupDigits(rest)}`;

  return `'${formattedIntl}`;   // force text for Sheets
}

return {
  json: {

    // BUSINESS INFO
    website: safe($json.website),
    name: safe($json.name),

    //  PHONE SAFE FORMAT
    phone: formatPhone($json.phone),

    rating: safe($json.rating),
    type: safe($json.type),

    // EMAIL
    email: safe($json.email),
    emailStatus: safe($json.emailStatus),

    // SOCIALS
    instagram: safe($json.instagram),
    facebook: safe($json.facebook),
    linkedin: safe($json.linkedin),
    twitter: safe($json.twitter),
    youtube: safe($json.youtube),
    tiktok: safe($json.tiktok),

    // CONFIDENCE
    instagramConfidence: safe($json.instagramConfidence),
    facebookConfidence: safe($json.facebookConfidence),
    linkedinConfidence: safe($json.linkedinConfidence),
    twitterConfidence: safe($json.twitterConfidence),
    youtubeConfidence: safe($json.youtubeConfidence),
    tiktokConfidence: safe($json.tiktokConfidence)
  }
};

