parameters.jsCode:
let raw = $json.response || "";

// extract JSON block
const match = raw.match(/\{[\s\S]*\}/);

let parsed = null;

try {
  parsed = match ? JSON.parse(match[0]) : null;
} catch (e) {
  parsed = null;
}

// fallback intelligent generation
const services =
  parsed?.services?.length
    ? parsed.services.join(", ")
    : ($json.type
        ? `${$json.type}`
        : "Local business services");

const summary =
  parsed?.summary
    ? parsed.summary
    : `${$json.name} is a local ${$json.type || "business"} offering quality products and services to its community.`;

return {
  ...$json,
  services,
  summary
};

let msg = $json.response || "";

// remove intro lines AI sometimes adds
msg = msg.replace(/Here is.*?:/i, "").trim();

// remove quotes
msg = msg.replace(/^["']|["']$/g, "");

// remove extra newlines
msg = msg.replace(/\n+/g, " ");

return {
  json: {
    ...$json,
    message: msg
  }
};

let score = 0;

const website = $json.website || "-";
const rating = Number($json.rating) || 0;
const emailStatus = $json.emailStatus || "NOT_FOUND";

const socials = [
  $json.instagram,
  $json.facebook,
  $json.linkedin,
  $json.twitter,
  $json.tiktok,
  $json.youtube
];

// count socials safely
const activeSocials = socials.filter(
  s => s && s !== "-" && s !== ""
).length;


//  WEBSITE (credibility)
if (website !== '-') score += 2;
else score += 1; // still a valid lead


// INSTAGRAM (best outreach channel)
if ($json.instagram && $json.instagram !== "-") score += 2;


// MULTIPLE SOCIALS (brand presence)
if (activeSocials >= 3) score += 3;
else if (activeSocials >= 1) score += 2;


// RATING QUALITY
if (rating >= 4.6) score += 2;
else if (rating >= 4.2) score += 1;


// EMAIL VALIDITY (direct contact)
if (emailStatus === "VALID") score += 1;


// GROWTH OPPORTUNITY BONUS
// businesses without socials are easy wins
if (activeSocials === 0) score += 1;

if ($json.instagram && website === '-') score += 2;



// normalize to max 10
score = Math.min(Math.round(score), 10);

return {
  ...$json,
  leadScore: `${score}/10`
};

const text = JSON.stringify($json);

// find first match helper
function find(pattern) {
  const match = text.match(pattern);
  return match ? match[0] : "-";
}

return {
  ...$json,

  serperInstagram: find(/https?:\/\/(www\.)?instagram\.com\/(?!reel|p\/)[^"& ]+/i),

  serperFacebook: find(/https?:\/\/(www\.)?facebook\.com\/(?!share|sharer|videos)[^"& ]+/i),

  serperLinkedin: find(/https?:\/\/(www\.)?linkedin\.com\/company\/[^"& ]+/i),

  serperTwitter: find(/https?:\/\/(twitter|x)\.com\/[^"& ]+/i),

  serperYoutube: find(/https?:\/\/(www\.)?youtube\.com\/(@|channel|c\/)[^"& ]+/i),

  serperTiktok: find(/https?:\/\/(www\.)?tiktok\.com\/@[^"& ]+/i)
};
